'use server';

import { updateTag } from 'next/cache';
import { insertPost } from './lib/posts';

export type CreatePostState = {
  error?: string;
  success?: boolean;
};

export async function createPost(
  _previousState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title');
  const content = formData.get('content');

  if (typeof title !== 'string' || !title.trim()) {
    return { error: 'A title is required.' };
  }

  if (typeof content !== 'string' || !content.trim()) {
    return { error: 'Content is required.' };
  }

  await insertPost(title.trim(), content.trim());

  // updateTag, unlike revalidateTag('posts', 'max'), expires the entry
  // immediately. The next render blocks for fresh data (read-your-own-writes).
  updateTag('posts');

  return { success: true };
}

