import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

// This is deliberately kept server-side. Replace this store with the application's
// database in production; the cache/invalidation contract remains the same.
const posts: Post[] = [];

export async function insertPost(title: string, content: string): Promise<Post> {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  posts.unshift(post);
  return post;
}

const getCachedPosts = unstable_cache(
  async () => posts,
  ['posts-list'],
  { tags: ['posts'] },
);

export async function getPosts(): Promise<Post[]> {
  return getCachedPosts();
}

